// ApiResponse.kt
sealed class ApiResponse<out T> {
    data class Success<T>(val data: T) : ApiResponse<T>()
    data class Error(val message: String, val code: Int? = null) : ApiResponse<Nothing>()
    object Loading : ApiResponse<Nothing>()
}

// AuthInterceptor.kt
import okhttp3.Interceptor
import okhttp3.Response

class AuthInterceptor : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val originalRequest = chain.request()
        val token = NetworkConfig.authToken
        
        val request = if (!token.isNullOrBlank()) {
            originalRequest.newBuilder()
                .header("Authorization", "Bearer $token")
                .build()
        } else {
            originalRequest
        }
        
        return chain.proceed(request)
    }
}

// UserApiService.kt
import retrofit2.Response
import retrofit2.http.GET
import retrofit2.http.Path
import retrofit2.http.Query

interface UserApiService {
    @GET("users/{userId}")
    suspend fun getUserProfile(@Path("userId") userId: Long): Response<User>
    
    @GET("users")
    suspend fun getUsers(
        @Query("page") page: Int = 1,
        @Query("limit") limit: Int = 20
    ): Response<List<User>>
}

// RetrofitClient.kt
import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

object RetrofitClient {
    private const val CONNECT_TIMEOUT = 30L
    private const val READ_TIMEOUT = 30L
    private const val WRITE_TIMEOUT = 30L
    
    private fun createOkHttpClient(): OkHttpClient {
        val loggingInterceptor = HttpLoggingInterceptor().apply {
            level = if (BuildConfig.DEBUG) {
                HttpLoggingInterceptor.Level.BODY
            } else {
                HttpLoggingInterceptor.Level.NONE
            }
        }
        
        return OkHttpClient.Builder()
            .addInterceptor(AuthInterceptor())
            .addInterceptor(loggingInterceptor)
            .connectTimeout(CONNECT_TIMEOUT, TimeUnit.SECONDS)
            .readTimeout(READ_TIMEOUT, TimeUnit.SECONDS)
            .writeTimeout(WRITE_TIMEOUT, TimeUnit.SECONDS)
            .build()
    }
    
    private fun createRetrofit(): Retrofit {
        return Retrofit.Builder()
            .baseUrl(NetworkConfig.currentEnvironment.baseUrl)
            .client(createOkHttpClient())
            .addConverterFactory(GsonConverterFactory.create())
            .build()
    }
    
    val userApiService: UserApiService by lazy {
        createRetrofit().create(UserApiService::class.java)
    }
    
    fun updateEnvironment(environment: Environment) {
        NetworkConfig.currentEnvironment = environment
    }
}

// UserRepository.kt
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import retrofit2.Response

class UserRepository {
    private val apiService = RetrofitClient.userApiService
    
    suspend fun getUserProfile(userId: Long): ApiResponse<User> = withContext(Dispatchers.IO) {
        try {
            val response = apiService.getUserProfile(userId)
            handleResponse(response)
        } catch (e: Exception) {
            ApiResponse.Error(e.message ?: "Unknown error occurred")
        }
    }
    
    suspend fun getUsers(page: Int = 1, limit: Int = 20): ApiResponse<List<User>> = 
        withContext(Dispatchers.IO) {
            try {
                val response = apiService.getUsers(page, limit)
                handleResponse(response)
            } catch (e: Exception) {
                ApiResponse.Error(e.message ?: "Unknown error occurred")
            }
        }
    
    private fun <T> handleResponse(response: Response<T>): ApiResponse<T> {
        return if (response.isSuccessful) {
            response.body()?.let {
                ApiResponse.Success(it)
            } ?: ApiResponse.Error("Empty response body", response.code())
        } else {
            ApiResponse.Error(
                response.errorBody()?.string() ?: "Request failed",
                response.code()
            )
        }
    }
}

// NetworkModule.kt
object NetworkModule {
    private val userRepository = UserRepository()
    
    fun setAuthToken(token: String) {
        NetworkConfig.authToken = token
    }
    
    fun clearAuthToken() {
        NetworkConfig.authToken = null
    }
    
    fun setEnvironment(environment: Environment) {
        RetrofitClient.updateEnvironment(environment)
    }
    
    suspend fun fetchUserProfile(userId: Long): ApiResponse<User> {
        return userRepository.getUserProfile(userId)
    }
    
    suspend fun fetchUsers(page: Int = 1, limit: Int = 20): ApiResponse<List<User>> {
        return userRepository.getUsers(page, limit)
    }
}

